#include <CL/cl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <stdint.h>

#include "../common.h"
#include "../util/timer/timer.h"

// OpenCL kernel source
const char *kernel_source = 
"#define DEFAULT_ORDER 508\n"
"\n"
"typedef struct {\n"
"    int value;\n"
"} record;\n"
"\n"
"typedef struct {\n"
"    int location;\n"
"    int indices[DEFAULT_ORDER + 1];\n"
"    int keys[DEFAULT_ORDER + 1];\n"
"    char is_leaf;\n"
"    int num_keys;\n"
"} knode;\n"
"\n"
"kernel void findK(\n"
"    long maxheight,\n"
"    const global knode *knodes,\n"
"    long knodes_elem,\n"
"    const global record *records,\n"
"    global long *currKnode,\n"
"    global long *offset,\n"
"    global int *keys,\n"
"    global record *ans)\n"
"{\n"
"    int bid = get_group_id(0);\n"
"    int thid = get_local_id(0);\n"
"    int threadsPerBlock = get_local_size(0);\n"
"    \n"
"    long current_offset = offset[bid];\n"
"    long current_knode = currKnode[bid];\n"
"    int key_val = keys[bid];\n"
"    \n"
"    for (int i = 0; i < maxheight; i++) {\n"
"        if (thid < threadsPerBlock) {\n"
"            if ((knodes[current_knode].keys[thid] <= key_val) && \n"
"                (knodes[current_knode].keys[thid + 1] > key_val)) {\n"
"                \n"
"                if (knodes[current_offset].indices[thid] < knodes_elem) {\n"
"                    current_offset = knodes[current_offset].indices[thid];\n"
"                }\n"
"            }\n"
"        }\n"
"        current_knode = current_offset;\n"
"    }\n"
"    \n"
"    currKnode[bid] = current_knode;\n"
"    offset[bid] = current_offset;\n"
"    \n"
"    if (thid < threadsPerBlock) {\n"
"        if (knodes[current_knode].keys[thid] == key_val) {\n"
"            ans[bid].value = records[knodes[current_knode].indices[thid]].value;\n"
"        }\n"
"    }\n"
"}\n";

void kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	long long time0;
	long long time1;
	long long time2;

	time0 = get_time();

	cl_int error;
	cl_uint num_platforms;
	error = clGetPlatformIDs(0, NULL, &num_platforms);
	if (error != CL_SUCCESS) { fprintf(stderr, "Error: %d\n", error); exit(1); }

	cl_platform_id *platforms = malloc(sizeof(cl_platform_id) * num_platforms);
	error = clGetPlatformIDs(num_platforms, platforms, NULL);
	if (error != CL_SUCCESS) { free(platforms); exit(1); }

	cl_platform_id platform = platforms[0];
	cl_uint devices_size;
	error = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 0, NULL, &devices_size);
	if (error != CL_SUCCESS || devices_size == 0) { free(platforms); exit(1); }

	cl_device_id *devices = malloc(devices_size);
	error = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, devices_size, devices, NULL);
	if (error != CL_SUCCESS) { free(platforms); free(devices); exit(1); }

	cl_device_id device = devices[0];

	cl_context_properties props[] = { CL_CONTEXT_PLATFORM, (cl_context_properties)platform, 0 };
	cl_context context = clCreateContextFromType(props, CL_DEVICE_TYPE_ALL, NULL, NULL, &error);
	if (error != CL_SUCCESS) { free(platforms); free(devices); exit(1); }

	cl_command_queue queue = clCreateCommandQueue(context, device, 0, &error);
	if (error != CL_SUCCESS) { free(platforms); free(devices); clReleaseContext(context); exit(1); }

	time1 = get_time();

	cl_program program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &error);
	if (error != CL_SUCCESS) { /* handle error */ }

	char opts[256];
	sprintf(opts, "-DDEFAULT_ORDER=%d", order);
	error = clBuildProgram(program, 1, &device, opts, NULL, NULL);
	if (error != CL_SUCCESS) { /* handle error */ }

	cl_kernel kernel = clCreateKernel(program, "findK", &error);
	if (error != CL_SUCCESS) { /* handle error */ }

	cl_mem recordsD = clCreateBuffer(context, CL_MEM_READ_ONLY, count * sizeof(record), NULL, &error);
	cl_mem knodesD = clCreateBuffer(context, CL_MEM_READ_ONLY, knodes_elem * sizeof(knode), NULL, &error);
	cl_mem currKnodeD = clCreateBuffer(context, CL_MEM_READ_WRITE, count * sizeof(long), NULL, &error);
	cl_mem offsetD = clCreateBuffer(context, CL_MEM_READ_WRITE, count * sizeof(long), NULL, &error);
	cl_mem keysD = clCreateBuffer(context, CL_MEM_READ_ONLY, count * sizeof(int), NULL, &error);
	cl_mem ansD = clCreateBuffer(context, CL_MEM_WRITE_ONLY, count * sizeof(record), NULL, &error);

	clEnqueueWriteBuffer(queue, recordsD, CL_TRUE, 0, count * sizeof(record), records, 0, NULL, NULL);
	clEnqueueWriteBuffer(queue, knodesD, CL_TRUE, 0, knodes_elem * sizeof(knode), knodes, 0, NULL, NULL);
	clEnqueueWriteBuffer(queue, currKnodeD, CL_TRUE, 0, count * sizeof(long), currKnode, 0, NULL, NULL);
	clEnqueueWriteBuffer(queue, offsetD, CL_TRUE, 0, count * sizeof(long), offset, 0, NULL, NULL);
	clEnqueueWriteBuffer(queue, keysD, CL_TRUE, 0, count * sizeof(int), keys, 0, NULL, NULL);

	int threadsPerBlock = order < 1024 ? order : 1024;
	size_t global = count * threadsPerBlock;
	size_t local = threadsPerBlock;

	clSetKernelArg(kernel, 0, sizeof(long), &maxheight);
	clSetKernelArg(kernel, 1, sizeof(cl_mem), &knodesD);
	clSetKernelArg(kernel, 2, sizeof(long), &knodes_elem);
	clSetKernelArg(kernel, 3, sizeof(cl_mem), &recordsD);
	clSetKernelArg(kernel, 4, sizeof(cl_mem), &currKnodeD);
	clSetKernelArg(kernel, 5, sizeof(cl_mem), &offsetD);
	clSetKernelArg(kernel, 6, sizeof(cl_mem), &keysD);
	clSetKernelArg(kernel, 7, sizeof(cl_mem), &ansD);

	clEnqueueNDRangeKernel(queue, kernel, 1, NULL, &global, &local, 0, NULL, NULL);
	clFinish(queue);

	clEnqueueReadBuffer(queue, ansD, CL_TRUE, 0, count * sizeof(record), ans, 0, NULL, NULL);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time2-time0)*100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time2-time0)*100);
	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2-time0)/1000000);

	// Cleanup
	clReleaseKernel(kernel);
	clReleaseProgram(program);
	clReleaseMemObject(recordsD);
	clReleaseMemObject(knodesD);
	clReleaseMemObject(currKnodeD);
	clReleaseMemObject(offsetD);
	clReleaseMemObject(keysD);
	clReleaseMemObject(ansD);
	clReleaseCommandQueue(queue);
	clReleaseContext(context);
	free(platforms);
	free(devices);
}
